-- ==========================================
-- 1. CREACIÓN DE LA TABLA 'operadores'
-- ==========================================
CREATE TABLE IF NOT EXISTS public.operadores (
    id_perfil int8 PRIMARY KEY,
    nombre_real text NOT NULL,
    agencia text,
    estado text DEFAULT 'Activo',
    fecha_ingreso date DEFAULT CURRENT_DATE
);

-- Habilitar Políticas de Seguridad a Nivel de Fila (RLS)
ALTER TABLE public.operadores ENABLE ROW LEVEL SECURITY;

-- Permiso de lectura pública para que index.html pueda mostrar los nombres en el Ranking
DROP POLICY IF EXISTS "Permitir lectura publica a operadores" ON public.operadores;
CREATE POLICY "Permitir lectura publica a operadores" 
    ON public.operadores 
    FOR SELECT 
    USING (true);

-- Permiso para que el administrador pueda editar, actualizar e insertar desde la UI o directamente
DROP POLICY IF EXISTS "Permitir edición a todos los roles" ON public.operadores;
CREATE POLICY "Permitir edición a todos los roles" 
    ON public.operadores 
    FOR ALL 
    USING (true)
    WITH CHECK (true);

